import groovy.json.JsonOutput
import groovy.json.JsonSlurper
import java.net.http.HttpClient
import java.net.http.HttpRequest
import java.net.http.HttpResponse
import java.time.Duration

success = false
publishedUrl = null
externalPostId = null
errorMessage = null

try {
    def sessionToken = platformConfig.apiKey
    def publicationUrl = platformConfig.username?.replaceAll('/+$', '')

    if (!sessionToken) {
        errorMessage = "Substack session token (apiKey) not configured"
        return
    }
    if (!publicationUrl) {
        errorMessage = "Substack publication URL (username) not configured"
        return
    }

    // Build Prosemirror document from finalContent (split on blank lines = paragraphs)
    def paragraphs = (post.finalContent as String).split(/\n\n+/).collect { para ->
        def lines = para.trim()
        if (!lines) return null
        [
            type: "paragraph",
            content: [[type: "text", text: lines]]
        ]
    }.findAll { it != null }

    if (!paragraphs) {
        paragraphs = [[type: "paragraph", content: [[type: "text", text: post.finalContent as String]]]]
    }

    def prosemirrorDoc = [type: "doc", content: paragraphs]

    def requestBody = [
        draft_title:    post.headline ?: "",
        draft_subtitle: post.draftContent ?: "",
        draft_body:     JsonOutput.toJson(prosemirrorDoc),
        draft_bylines:  [],
        audience:       "everyone"
    ]

    def hostname = new URL(publicationUrl).host
    def apiUrl = "${publicationUrl}/api/v1/drafts"
    def cookieHeader = "substack.sid=${sessionToken}; connect.sid=${sessionToken}"

    def httpClient = HttpClient.newBuilder()
        .connectTimeout(Duration.ofSeconds(15))
        .build()

    def request = HttpRequest.newBuilder()
        .uri(URI.create(apiUrl))
        .header("Content-Type", "application/json")
        .header("Cookie", cookieHeader)
        .header("Referer", "${publicationUrl}/publish/post")
        .header("Origin", publicationUrl)
        .POST(HttpRequest.BodyPublishers.ofString(JsonOutput.toJson(requestBody)))
        .timeout(Duration.ofSeconds(30))
        .build()

    def response = httpClient.send(request, HttpResponse.BodyHandlers.ofString())
    def responseBody = response.body()

    ec.logger.info("Substack API response [${response.statusCode()}]: ${responseBody?.take(500)}")

    if (!(response.statusCode() in [200, 201])) {
        errorMessage = "Substack API error ${response.statusCode()}: ${responseBody?.take(300)}"
        return
    }
    def parsed = new JsonSlurper().parseText(responseBody)
    def draftId = parsed?.id
    if (!draftId) {
        errorMessage = "Substack draft created but no id in response: ${responseBody?.take(300)}"
        return
    }

    // Publish the draft; send: true also emails the post to all subscribers
    def publishRequest = HttpRequest.newBuilder()
        .uri(URI.create("${publicationUrl}/api/v1/drafts/${draftId}/publish"))
        .header("Content-Type", "application/json")
        .header("Cookie", cookieHeader)
        .header("Referer", "${publicationUrl}/publish/post/${draftId}")
        .header("Origin", publicationUrl)
        .POST(HttpRequest.BodyPublishers.ofString(JsonOutput.toJson([send: true])))
        .timeout(Duration.ofSeconds(30))
        .build()

    def publishResponse = httpClient.send(publishRequest, HttpResponse.BodyHandlers.ofString())
    def publishBody = publishResponse.body()

    ec.logger.info("Substack publish response [${publishResponse.statusCode()}]: ${publishBody?.take(500)}")

    if (publishResponse.statusCode() in [200, 201]) {
        def published = new JsonSlurper().parseText(publishBody)
        externalPostId = (published?.id ?: draftId) as String
        publishedUrl = published?.canonical_url ?:
            (published?.slug ? "${publicationUrl}/p/${published.slug}" :
                "${publicationUrl}/publish/post/${draftId}")
        success = true
    } else {
        errorMessage = "Substack publish step failed ${publishResponse.statusCode()}: " +
            "${publishBody?.take(300)} — draft kept at ${publicationUrl}/publish/post/${draftId}"
    }

} catch (Exception e) {
    errorMessage = "Substack publishing failed: ${e.message}"
    ec.logger.error("Substack publish error", e)
}

import groovy.json.JsonOutput
import groovy.json.JsonSlurper
import java.net.http.HttpClient
import java.net.http.HttpRequest
import java.net.http.HttpResponse
import java.time.Duration

success = false
publishedUrl = null
errorMessage = null

try {
    def accessToken = platformConfig.apiKey
    def personUrn   = platformConfig.username

    if (!accessToken) {
        errorMessage = "LinkedIn access token (apiKey) not configured"
        return
    }
    if (!personUrn) {
        errorMessage = "LinkedIn person URN (username) not configured — expected format: urn:li:person:XXXXX"
        return
    }

    // Build post text: headline + finalContent
    def postText = new StringBuilder()
    if (post.headline) postText.append(post.headline).append("\n\n")
    postText.append(post.finalContent ?: "")

    def requestBody = [
        author: personUrn,
        lifecycleState: "PUBLISHED",
        specificContent: [
            "com.linkedin.ugc.ShareContent": [
                shareCommentary: [
                    text: postText.toString()
                ],
                shareMediaCategory: "NONE"
            ]
        ],
        visibility: [
            "com.linkedin.ugc.MemberNetworkVisibility": "PUBLIC"
        ]
    ]

    def httpClient = HttpClient.newBuilder()
        .connectTimeout(Duration.ofSeconds(15))
        .build()

    def request = HttpRequest.newBuilder()
        .uri(URI.create("https://api.linkedin.com/v2/ugcPosts"))
        .header("Authorization", "Bearer ${accessToken}")
        .header("Content-Type", "application/json")
        .header("X-Restli-Protocol-Version", "2.0.0")
        .POST(HttpRequest.BodyPublishers.ofString(JsonOutput.toJson(requestBody)))
        .timeout(Duration.ofSeconds(30))
        .build()

    def response = httpClient.send(request, HttpResponse.BodyHandlers.ofString())
    def responseBody = response.body()

    ec.logger.info("LinkedIn API response [${response.statusCode()}]: ${responseBody?.take(500)}")

    if (response.statusCode() == 201) {
        // LinkedIn returns the post URN in X-RestLi-Id header
        def postUrn = response.headers().firstValue("X-RestLi-Id").orElse(null)
        if (postUrn) {
            // URN format: urn:li:ugcPost:XXXXXXXXXX
            def postId = postUrn.tokenize(':').last()
            publishedUrl = "https://www.linkedin.com/feed/update/${postUrn}/"
        } else {
            publishedUrl = "https://www.linkedin.com/feed/"
        }
        success = true
    } else {
        errorMessage = "LinkedIn API error ${response.statusCode()}: ${responseBody?.take(300)}"
    }

} catch (Exception e) {
    errorMessage = "LinkedIn publishing failed: ${e.message}"
    ec.logger.error("LinkedIn publish error", e)
}

import groovy.json.JsonSlurper
import java.net.http.HttpClient
import java.net.http.HttpRequest
import java.net.http.HttpResponse
import java.time.Duration
import java.net.URLEncoder

success = false
publishedUrl = null
errorMessage = null

try {
    def accessToken = platformConfig.apiKey
    def pageId      = platformConfig.username

    if (!accessToken) { errorMessage = "Facebook page access token (apiKey) not configured"; return }
    if (!pageId)      { errorMessage = "Facebook Page id (username) not configured"; return }

    def message = new StringBuilder()
    if (post.headline) message.append(post.headline).append("\n\n")
    message.append(post.finalContent ?: "")

    def form = "message=" + URLEncoder.encode(message.toString(), "UTF-8") +
               "&access_token=" + URLEncoder.encode(accessToken as String, "UTF-8")

    def httpClient = HttpClient.newBuilder().connectTimeout(Duration.ofSeconds(15)).build()
    def request = HttpRequest.newBuilder()
        .uri(URI.create("https://graph.facebook.com/v19.0/${pageId}/feed"))
        .header("Content-Type", "application/x-www-form-urlencoded")
        .POST(HttpRequest.BodyPublishers.ofString(form))
        .timeout(Duration.ofSeconds(30))
        .build()

    def response = httpClient.send(request, HttpResponse.BodyHandlers.ofString())
    def responseBody = response.body()
    ec.logger.info("Facebook API response [${response.statusCode()}]: ${responseBody?.take(500)}")

    if (response.statusCode() == 200) {
        def parsed = new JsonSlurper().parseText(responseBody)
        def id = parsed?.id
        publishedUrl = id ? "https://www.facebook.com/${id}" : "https://www.facebook.com/${pageId}"
        success = true
    } else {
        errorMessage = "Facebook API error ${response.statusCode()}: ${responseBody?.take(300)}"
    }
} catch (Exception e) {
    errorMessage = "Facebook publishing failed: ${e.message}"
    ec.logger.error("Facebook publish error", e)
}

import groovy.json.JsonOutput
import groovy.json.JsonSlurper
import java.net.http.HttpClient
import java.net.http.HttpRequest
import java.net.http.HttpResponse
import java.time.Duration

success = false
publishedUrl = null
errorMessage = null

try {
    def token    = platformConfig.apiKey
    def authorId = platformConfig.username

    if (!token)    { errorMessage = "Medium integration token (apiKey) not configured"; return }
    if (!authorId) { errorMessage = "Medium authorId (username) not configured"; return }

    def requestBody = [
        title:         post.headline ?: "Untitled",
        contentFormat: "markdown",
        content:       post.finalContent ?: "",
        publishStatus: "draft"
    ]

    def httpClient = HttpClient.newBuilder().connectTimeout(Duration.ofSeconds(15)).build()
    def request = HttpRequest.newBuilder()
        .uri(URI.create("https://api.medium.com/v1/users/${authorId}/posts"))
        .header("Authorization", "Bearer ${token}")
        .header("Content-Type", "application/json")
        .header("Accept", "application/json")
        .POST(HttpRequest.BodyPublishers.ofString(JsonOutput.toJson(requestBody)))
        .timeout(Duration.ofSeconds(30))
        .build()

    def response = httpClient.send(request, HttpResponse.BodyHandlers.ofString())
    def responseBody = response.body()
    ec.logger.info("Medium API response [${response.statusCode()}]: ${responseBody?.take(500)}")

    if (response.statusCode() in [200, 201]) {
        def parsed = new JsonSlurper().parseText(responseBody)
        publishedUrl = parsed?.data?.url ?: "https://medium.com/"
        success = true
    } else {
        errorMessage = "Medium API error ${response.statusCode()}: ${responseBody?.take(300)}"
    }
} catch (Exception e) {
    errorMessage = "Medium publishing failed: ${e.message}"
    ec.logger.error("Medium publish error", e)
}

import groovy.json.JsonOutput
import groovy.json.JsonSlurper
import java.net.http.HttpClient
import java.net.http.HttpRequest
import java.net.http.HttpResponse
import java.time.Duration
import java.net.URLEncoder
import javax.crypto.Mac
import javax.crypto.spec.SecretKeySpec
import java.util.Base64
import java.util.UUID

success = false
publishedUrl = null
externalPostId = null
errorMessage = null

def rfc3986Encode = { String s ->
    URLEncoder.encode(s, "UTF-8")
        .replace("+", "%20")
        .replace("*", "%2A")
        .replace("%7E", "~")
}

try {
    def consumerKey    = platformConfig.apiKey
    def consumerSecret = platformConfig.apiSecret
    def accessToken    = platformConfig.username
    def tokenSecret    = platformConfig.password

    if (!consumerKey)    { errorMessage = "X consumer key (apiKey) not configured"; return }
    if (!consumerSecret) { errorMessage = "X consumer secret (apiSecret) not configured"; return }
    if (!accessToken)    { errorMessage = "X access token (username) not configured"; return }
    if (!tokenSecret)    { errorMessage = "X access token secret (password) not configured"; return }

    def text = new StringBuilder()
    if (post.headline) text.append(post.headline).append("\n\n")
    text.append(post.finalContent ?: "")
    def tweetText = text.toString()
    if (tweetText.length() > 280) tweetText = tweetText.take(277) + "…"

    def apiUrl = "https://api.x.com/2/tweets"
    def oauthParams = [
        oauth_consumer_key    : consumerKey as String,
        oauth_nonce           : UUID.randomUUID().toString().replace("-", ""),
        oauth_signature_method: "HMAC-SHA1",
        oauth_timestamp       : (System.currentTimeMillis() / 1000L) as String,
        oauth_token           : accessToken as String,
        oauth_version         : "1.0"
    ]

    def paramString = oauthParams.sort().collect { k, v ->
        "${rfc3986Encode(k)}=${rfc3986Encode(v)}"
    }.join("&")
    def baseString = "POST&${rfc3986Encode(apiUrl)}&${rfc3986Encode(paramString)}"
    def signingKey = "${rfc3986Encode(consumerSecret as String)}&${rfc3986Encode(tokenSecret as String)}"

    def mac = Mac.getInstance("HmacSHA1")
    mac.init(new SecretKeySpec(signingKey.getBytes("UTF-8"), "HmacSHA1"))
    def signature = Base64.encoder.encodeToString(mac.doFinal(baseString.getBytes("UTF-8")))

    def authHeader = "OAuth " + (oauthParams + [oauth_signature: signature]).sort().collect { k, v ->
        "${rfc3986Encode(k)}=\"${rfc3986Encode(v)}\""
    }.join(", ")

    def httpClient = HttpClient.newBuilder().connectTimeout(Duration.ofSeconds(15)).build()
    def request = HttpRequest.newBuilder()
        .uri(URI.create(apiUrl))
        .header("Authorization", authHeader)
        .header("Content-Type", "application/json")
        .POST(HttpRequest.BodyPublishers.ofString(JsonOutput.toJson([text: tweetText])))
        .timeout(Duration.ofSeconds(30))
        .build()

    def response = httpClient.send(request, HttpResponse.BodyHandlers.ofString())
    def responseBody = response.body()
    ec.logger.info("X API response [${response.statusCode()}]: ${responseBody?.take(500)}")

    if (response.statusCode() == 201) {
        def parsed = new JsonSlurper().parseText(responseBody)
        externalPostId = parsed?.data?.id as String
        publishedUrl = externalPostId ? "https://x.com/i/web/status/${externalPostId}" : "https://x.com/"
        success = true
    } else {
        errorMessage = "X API error ${response.statusCode()}: ${responseBody?.take(300)}"
    }
} catch (Exception e) {
    errorMessage = "X publishing failed: ${e.message}"
    ec.logger.error("X publish error", e)
}
